package com.hospital.management.validation;
import com.hospital.management.model.AppointmentForm;import java.time.*;import java.time.format.*;import java.util.Set;
/** Validates appointment request syntax and time boundaries; availability remains service-authoritative. */
public class AppointmentValidator {private static final DateTimeFormatter TIME=DateTimeFormatter.ofPattern("HH:mm").withResolverStyle(ResolverStyle.STRICT);private static final Set<String>STATUS=Set.of("SCHEDULED","CONFIRMED","COMPLETED","CANCELLED","NO_SHOW");
public ValidationResult validateBooking(AppointmentForm f){return validate(f,true);}public ValidationResult validateReschedule(AppointmentForm f){ValidationResult r=validate(f,true);if(f==null||f.getAppointmentId()==null||f.getAppointmentId()<=0)r.addError("appointmentId","Valid appointment is required");return r;}public ValidationResult validateDetails(AppointmentForm f){ValidationResult r=new ValidationResult();if(f==null||f.getAppointmentId()==null||f.getAppointmentId()<=0)r.addError("appointmentId","Valid appointment is required");text(f==null?null:f.getReason(),f==null?null:f.getNotes(),r);return r;}
private ValidationResult validate(AppointmentForm f,boolean ids){ValidationResult r=new ValidationResult();if(f==null){r.addError("form","Appointment details are required");return r;}if(ids&&(f.getPatientId()==null||f.getPatientId()<=0))r.addError("patientId","Select a patient");if(ids&&(f.getDoctorId()==null||f.getDoctorId()<=0))r.addError("doctorId","Select a doctor");LocalDate d=null;LocalTime t=null;try{d=LocalDate.parse(f.getAppointmentDate());if(d.isBefore(LocalDate.now()))r.addError("appointmentDate","Appointment date cannot be in the past");}catch(Exception e){r.addError("appointmentDate","Enter date as yyyy-MM-dd");}try{t=LocalTime.parse(f.getStartTime(),TIME);}catch(Exception e){r.addError("startTime","Select a valid time");}if(d!=null&&t!=null&&d.equals(LocalDate.now())&&!t.isAfter(LocalTime.now()))r.addError("startTime","Select a future time");text(f.getReason(),f.getNotes(),r);if(f.getStatus()!=null&&!f.getStatus().isBlank()&&!STATUS.contains(f.getStatus().toUpperCase()))r.addError("status","Invalid appointment status");return r;}
private void text(String reason,String notes,ValidationResult r){String x=reason==null?"":reason.trim();if(x.length()<3||x.length()>500)r.addError("reason","Reason must be 3-500 characters");if(notes!=null&&notes.length()>1000)r.addError("notes","Notes must not exceed 1000 characters");}}
